"use strict";

// Obtém todos os itens do input (usado no n8n)
const input = $input.all();

/**
 * Gera entradas para os últimos 7 dias a partir da data base.
 * @param {Object} item - Item de entrada contendo a data base em item.json.date.
 * @returns {Object[]} Array de entradas com as datas formatadas em YYYY-MM-DD.
 */
function generateLastDaysEntries(item) {
  const entries = [];

  // Converte a data recebida para objeto Date
  const baseDate = new Date(item.json.date);

  // Gera entradas para os últimos 7 dias
  for (let i = item.json.date_historico; i >= 0; i--) { // De 6 a 0 para incluir a data base
    const dateEntry = new Date(baseDate);
    dateEntry.setDate(baseDate.getDate() - i); // Retrocede i dias
    entries.push({
      json: {
        ...item.json,
        since: dateEntry.toISOString().split("T")[0],
        until: dateEntry.toISOString().split("T")[0]
      }
    });
  }

  return entries;
}

// Processa cada item do input e gera a saída
const output = input.flatMap(item => generateLastDaysEntries(item));

// Ordena as entradas da data mais antiga até a mais atual
output.sort((a, b) => new Date(a.json.date) - new Date(b.json.date));

return output;

